CREATE TABLE SH.CUSTOMERS (
    CUST_ID NUMBER NOT NULL,
    CUST_FIRST_NAME VARCHAR2(20) NOT NULL,
    CUST_LAST_NAME VARCHAR2(40) NOT NULL,
    CUST_GENDER CHAR(1) NOT NULL,
    CUST_YEAR_OF_BIRTH NUMBER(4,0) NULL,
    CUST_MARITAL_STATUS VARCHAR2(20) NULL,
    CONSTRAINT PK_CUSTOMERS PRIMARY KEY (CUST_ID)
)
GO
CREATE TABLE SH.PRODUCTS (
    PROD_ID NUMBER NOT NULL,
    PROD_NAME VARCHAR2(50) NOT NULL,
    PROD_DESC VARCHAR2(4000) NULL,
    PROD_SUBCATEGORY VARCHAR2(50) NULL,
    CONSTRAINT PK_PRODUCTS PRIMARY KEY (PROD_ID)
)
GO
